var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐흠, 여긴 밤바다도 참 경치가 좋군.","JPN":"ふむ、ここの海は夜景も素晴らしいな。","ENG":"Hmm, even the night view is beautiful here.","TWN":"哇，海邊的夜景好美。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"촬영해 두었다가 박 교수에게 시뮬레이션으로 구현해 달라고 해도 좋겠어.","JPN":"撮影しておいて、オリヴィエ教授にシミュレーションで再現してほしいぐらいだ。","ENG":"Maybe I should film it and send it to Professor Park to create a simulation.","TWN":"我要把它拍下來給奧利維亞教授，讓她模擬一個假的出來。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그런데 릴리 양, 자네는 계속 날 따라다닐 생각인가?","JPN":"ところでリリー、君はずっと私について来るつもりかね？","ENG":"By the way, Lily, are you planning to follow me around all the time?","TWN":"我說莉莉，你打算繼續這樣跟著我嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"네. 저는 수면 담당이니까요.","JPN":"はい。私は熟眠担当ですから。","ENG":"Of course, I’m responsible for matters related to sleep.","TWN":"是的，因為我是負責主人的睡眠。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"원하실 때라면 언제든 안락한 수면을 취하실 수 있게, 주인님의 곁을 지켜야 합니다.","JPN":"お望みの際にいつでも快適な睡眠をとることができるよう、ご主人様のそばを守る必要があります。","ENG":"I have to stay with you so that you can comfortably rest whenever you want to sleep.","TWN":"為了幫助主人可以隨時得入眠，所以必須時時跟著主人。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하. 베로니카 양만큼 투철한 직업 정신이군.","JPN":"ハハハ。ベロニカに匹敵するプロのメイドさんだな。","ENG":"Hah hah, you’re just like Veronica. Very passionate about your work.","TWN":"哈哈，你跟貝洛妮卡一樣很敬業呢！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"감사합니다. 메이드장님에 비하기에는 아직 부족하지만요.","JPN":"ありがとうございます。メイド長と比べるにはまだ未熟ではありますが。","ENG":"Thank you, but I’m still not good enough when compared to the Chief Maid.","TWN":"謝謝！但我還沒資格跟女僕長相提並論。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"그보다 주인님, 곤경에 처한 마을을 도우시겠다는 뜻은 이해했습니다.","JPN":"ところでご主人様、困っている村人を助けたいという意志は理解できました。","ENG":"Master, I understand you want to help this village in trouble.","TWN":"主人，您的意思是想幫助處於困境的村莊對吧？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"저한테 꿀잼인 방안이 있어요. 들어 보시겠습니까?","JPN":"私にやばたにえんな方法があります。聞いてくださいませんか？","ENG":"I have one very LMAO solution. Do you care to listen?","TWN":"那我有個有趣的提議，您要聽聽嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오, 그래? 어떤 방안인가?","JPN":"おお、そうか？　どんな方法だ？","ENG":"Oh? What is it?","TWN":"喔，是嗎？說來聽聽！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"경계가 해이해지는 동틀 무렵에 용병들의 주둔지와 리조트로 침입하는 겁니다.","JPN":"警戒が緩む明け方に、傭兵のアジトとリゾートに侵入するのです。","ENG":"We sneak into the mercenaries’ outpost and resort at dawn when their guard is down.","TWN":"趁天快亮之前警戒正鬆懈的時候，偷襲傭兵的營地和度假村。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"주요 인사들만 <color=#ffd34c>처분</color>하면 다른 이들은 자연스럽게 서렌을 치겠죠.","JPN":"重役だけを<color=#ffd34c>処分</color>すれば、他の人は自然と身を引くでしょう。","ENG":"Then we <color=#ffd34c>terminate</color> high value targets and rest of them will go GG.","TWN":"所謂<color=#ffd34c>擒賊先擒王</color>，只要先除掉老大，其他人自然會乖乖就範。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"처분이라면……. 맨션의 해결 방식인가?","JPN":"処分ということは……マンションのやり方か。","ENG":"Terminate... Is that how the Mansion solves its problems?","TWN":"所以你的意思是…要用曼森的方式處理嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그 제안은 못 들은 걸로 하겠네.","JPN":"その提案は聞かなかったことにする。","ENG":"I’ll just pretend I didn’t hear that.","TWN":"這個提議我會當作沒聽到。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"맨션의 방식이 거슬리실 수도 있지만, 그게 마을을 돕는 가장 쉬운 길입니다.","JPN":"マンションのやり方で気が進まないかもしれませんが、それが村を助ける一番簡単な方法です。","ENG":"You might not like it, but it’s the easiest way.","TWN":"雖然曼森的方式不光彩，但這是幫助村莊最容易的方法。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"손에 피를 묻히고 끝낼 생각이었다면 진즉 그랬겠지.","JPN":"手を血に染めてまで終わらせるつもりだったら、最初からそうしただろう。","ENG":"I would have done it already if I was willing to use violence.","TWN":"如果打打殺殺就能解決問題，那我早就這麼做了。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자네가 말한 방식으로 해결해도 마을 사람들은 기뻐하지 않을 거야. 내가 장담하지.","JPN":"しかし、君の提案どおりにして解決しても、村人は喜ばない。私が断言する。","ENG":"I don’t think the villagers will be happy to see their troubles go away like that either. I’m sure of it.","TWN":"只是我敢保證，若是用你說的方式解決，那村裡的人也不會高興的。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"하지만…….","JPN":"しかし……","ENG":"But...","TWN":"可是…"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};